#include <stdint.h>
#include <riscv_esp32p4.h>

// Test ZERO.QACC - Zero QACC accumulator
// QACC is used internally, stored to memory to ensure complete Data flow
// CHECK-LABEL: define dso_local ptr @test_zero_qacc(
// CHECK-SAME: ptr noundef [[DST:%.*]]) local_unnamed_addr #[[ATTR0:[0-9]+]] {
// CHECK-NEXT:  [[ENTRY:.*:]]
// CHECK-NEXT:    [[TMP0:%.*]] = tail call { <16 x i8>, <16 x i8>, <16 x i8>, <16 x i8> } @llvm.riscv.esp.zero.qacc.m()
// CHECK-NEXT:    [[TMP1:%.*]] = extractvalue { <16 x i8>, <16 x i8>, <16 x i8>, <16 x i8> } [[TMP0]], 0
// CHECK-NEXT:    [[TMP2:%.*]] = tail call ptr @llvm.riscv.esp.st.qacc.l.l.128.ip.m(<16 x i8> [[TMP1]], ptr [[DST]], i32 16)
// CHECK-NEXT:    ret ptr [[TMP2]]
//
void *test_zero_qacc(void *dst) {
    esp_qacc_4x128_t qacc = esp_zero_qacc_m();
    // Store QACC_L[127:0] to memory to ensure complete Data flow
    return __builtin_riscv_esp_st_qacc_l_l_128_ip_m(qacc.v0, dst, 16);
}

